{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://esaa.local/schemas/agent_result.schema.json",
  "title": "ESAA Agent Result Envelope",
  "$comment": "v0.4.1 — prior_status obrigatório; allOf condicional garante coerência entre action e prior_status; file_updates sem complete é inválido via WG-002.",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "activity_event"
  ],
  "properties": {
    "activity_event": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "action",
        "task_id",
        "prior_status"
      ],
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "claim",
            "complete",
            "review",
            "issue.report"
          ]
        },
        "task_id": {
          "type": "string",
          "minLength": 1
        },
        "prior_status": {
          "$comment": "Status da tarefa no roadmap no momento da invocação. Declarado pelo agente e validado pelo Orchestrator via WG-003 antes de qualquer transição.",
          "type": "string",
          "enum": [
            "todo",
            "in_progress",
            "review"
          ]
        },
        "notes": {
          "type": "string"
        },
        "verification": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "checks"
          ],
          "properties": {
            "checks": {
              "type": "array",
              "items": {
                "type": "string",
                "minLength": 1
              },
              "minItems": 1
            }
          }
        },
        "decision": {
          "type": "string",
          "enum": [
            "approve",
            "request_changes"
          ]
        },
        "tasks": {
          "type": "array",
          "items": {
            "type": "string",
            "minLength": 1
          },
          "minItems": 1
        },
        "issue_id": {
          "type": "string",
          "minLength": 1
        },
        "fixes": {
          "type": "string",
          "minLength": 1
        },
        "severity": {
          "type": "string",
          "enum": [
            "low",
            "medium",
            "high",
            "critical"
          ]
        },
        "title": {
          "type": "string",
          "minLength": 1
        },
        "category": {
          "type": "string"
        },
        "subtype": {
          "type": "string"
        },
        "affected": {
          "type": "object",
          "additionalProperties": false,
          "properties": {
            "baseline_id": {
              "type": "string"
            },
            "environment": {
              "type": "string"
            },
            "paths": {
              "type": "array",
              "items": {
                "type": "string",
                "minLength": 1
              }
            }
          }
        },
        "evidence": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "symptom",
            "repro_steps"
          ],
          "properties": {
            "symptom": {
              "type": "string",
              "minLength": 1
            },
            "repro_steps": {
              "type": "array",
              "items": {
                "type": "string",
                "minLength": 1
              },
              "minItems": 1
            }
          }
        },
        "discovery_evidence": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "unknowns",
            "assumptions",
            "critical_questions"
          ],
          "properties": {
            "unknowns": {
              "type": "array",
              "items": {
                "type": "string",
                "minLength": 1
              }
            },
            "assumptions": {
              "type": "array",
              "items": {
                "type": "string",
                "minLength": 1
              }
            },
            "critical_questions": {
              "type": "array",
              "items": {
                "type": "string",
                "minLength": 1
              }
            }
          }
        },
        "lesson": {
          "type": "object",
          "additionalProperties": false,
          "required": [
            "mistake",
            "rule",
            "scope",
            "enforcement"
          ],
          "properties": {
            "mistake": {
              "type": "string",
              "minLength": 1
            },
            "rule": {
              "type": "string",
              "minLength": 1
            },
            "scope": {
              "type": "object",
              "additionalProperties": false,
              "required": [
                "task_kinds"
              ],
              "properties": {
                "task_kinds": {
                  "type": "array",
                  "items": {
                    "type": "string",
                    "enum": [
                      "spec",
                      "impl",
                      "qa"
                    ]
                  },
                  "minItems": 1
                }
              }
            },
            "enforcement": {
              "type": "object",
              "additionalProperties": false,
              "required": [
                "mode",
                "applies_to"
              ],
              "properties": {
                "mode": {
                  "type": "string",
                  "enum": [
                    "reject",
                    "warn",
                    "require_field",
                    "require_step"
                  ]
                },
                "applies_to": {
                  "type": "string",
                  "enum": [
                    "output_contract",
                    "boundaries",
                    "template",
                    "workflow_gate",
                    "verification_gate"
                  ]
                }
              }
            }
          }
        }
      },
      "allOf": [
        {
          "$comment": "RULE: action=claim só é válido se prior_status=todo",
          "if": {
            "properties": {
              "action": {
                "const": "claim"
              }
            },
            "required": [
              "action"
            ]
          },
          "then": {
            "properties": {
              "prior_status": {
                "const": "todo"
              }
            },
            "$comment": "claim sobre tarefa que não está em todo é sempre MISSING_CLAIM ou LOCK_VIOLATION"
          }
        },
        {
          "$comment": "RULE: action=complete só é válido se prior_status=in_progress e verification.checks presente",
          "if": {
            "properties": {
              "action": {
                "const": "complete"
              }
            },
            "required": [
              "action"
            ]
          },
          "then": {
            "properties": {
              "prior_status": {
                "const": "in_progress"
              }
            },
            "required": [
              "verification"
            ],
            "$comment": "complete sem verification é rejeitado por WG-002; prior_status errado é rejeitado por WG-003"
          }
        },
        {
          "$comment": "RULE: action=review só é válido se prior_status=review e decision+tasks presentes",
          "if": {
            "properties": {
              "action": {
                "const": "review"
              }
            },
            "required": [
              "action"
            ]
          },
          "then": {
            "properties": {
              "prior_status": {
                "const": "review"
              }
            },
            "required": [
              "decision",
              "tasks"
            ]
          }
        },
        {
          "$comment": "RULE: action=issue.report requer campos de evidência independente do prior_status",
          "if": {
            "properties": {
              "action": {
                "const": "issue.report"
              }
            },
            "required": [
              "action"
            ]
          },
          "then": {
            "required": [
              "issue_id",
              "severity",
              "title",
              "evidence"
            ]
          }
        }
      ]
    },
    "file_updates": {
      "$comment": "Presente apenas quando action=complete. O Orchestrator rejeita file_updates em qualquer outro action via WG-002 (MISSING_COMPLETE).",
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "path",
          "content"
        ],
        "properties": {
          "path": {
            "type": "string",
            "minLength": 1
          },
          "content": {
            "type": "string"
          }
        }
      }
    }
  },
  "allOf": [
    {
      "$comment": "RULE (root): file_updates só é permitido quando action=complete. Schema não pode proibir sozinho (file_updates é opcional), mas o Orchestrator aplica WG-002 para rejeitar file_updates com qualquer action != complete.",
      "if": {
        "required": [
          "file_updates"
        ]
      },
      "then": {
        "properties": {
          "activity_event": {
            "properties": {
              "action": {
                "const": "complete"
              }
            },
            "required": [
              "action"
            ]
          }
        }
      }
    }
  ]
}
